export type GuideFeature = { icon: string; text: string };
export type GuideStep = { icon: string; title: string; desc: string };

export type Guide = {
  emoji: string;
  title: string;
  tagline: string;
  /** 插畫 SVG（內嵌字串，viewBox 0 0 400 220） */
  svg: string;
  whatIs: string;
  features: GuideFeature[];
  steps: GuideStep[];
  /** 完整語音導覽稿（繁中口語） */
  voice: string;
};

/** 共用插畫底框：漸層背景 + 柔光，內容由 inner 填入 */
function scene(inner: string) {
  return `<svg viewBox="0 0 400 220" xmlns="http://www.w3.org/2000/svg" class="w-full h-auto">
    <defs>
      <linearGradient id="bg" x1="0" y1="0" x2="1" y2="1">
        <stop offset="0" stop-color="#1a1033"/><stop offset="1" stop-color="#0d0820"/>
      </linearGradient>
      <linearGradient id="pp" x1="0" y1="0" x2="1" y2="1">
        <stop offset="0" stop-color="#a855f7"/><stop offset="1" stop-color="#ec4899"/>
      </linearGradient>
      <linearGradient id="bl" x1="0" y1="0" x2="1" y2="1">
        <stop offset="0" stop-color="#6366f1"/><stop offset="1" stop-color="#22d3ee"/>
      </linearGradient>
    </defs>
    <rect width="400" height="220" rx="16" fill="url(#bg)"/>
    <circle cx="60" cy="40" r="70" fill="#a855f7" opacity="0.16"/>
    <circle cx="350" cy="200" r="80" fill="#ec4899" opacity="0.12"/>
    ${inner}
  </svg>`;
}

